import React from 'react';
import { useNavigate } from 'react-router-dom';

const Header = ({ userInfo }) => {
  const navigate = useNavigate();

  const handleLogout = () => {
    localStorage.removeItem('token');
    localStorage.removeItem('userInfo');
    navigate('/login');
  };

  return (
    <header style={{
      background: 'linear-gradient(135deg, #ffffff 0%, #f5f7fa 100%)',
      boxShadow: '0 2px 10px rgba(0, 0, 0, 0.05)',
      padding: '1rem 2rem',
      borderBottom: '1px solid rgba(0, 0, 0, 0.05)'
    }}>
      <div className="container-fluid">
        <div className="d-flex justify-content-between align-items-center">
          <div className="d-flex align-items-center">
            <img 
              src="/Logo/LSlogo.png" 
              alt="Loyalstring" 
              style={{ 
                height: '28px',
                marginRight: '16px'
              }} 
            />
            <h1 style={{
              fontSize: '1.5rem',
              fontWeight: 600,
              margin: 0,
              color: '#333',
              display: 'flex',
              alignItems: 'center'
            }}>
              <span style={{ 
                background: 'linear-gradient(45deg, #5470FF, #6C8FFF)',
                WebkitBackgroundClip: 'text',
                WebkitTextFillColor: 'transparent',
                marginRight: '8px'
              }}>
                RFID API
              </span>
              Dashboard
            </h1>
          </div>
          
          {userInfo && (
            <div className="d-flex align-items-center">
              <div style={{
                background: 'rgba(84, 112, 255, 0.1)',
                padding: '8px 16px',
                borderRadius: '20px',
                marginRight: '20px',
                display: 'flex',
                alignItems: 'center'
              }}>
                <i className="fas fa-user-circle me-2" style={{ color: '#5470FF' }}></i>
                <span style={{ 
                  fontWeight: 500,
                  color: '#333',
                  marginRight: '12px'
                }}>
                  {userInfo.Username}
                </span>
                <span style={{
                  background: 'rgba(84, 112, 255, 0.2)',
                  padding: '4px 8px',
                  borderRadius: '12px',
                  fontSize: '0.85rem',
                  color: '#5470FF',
                  fontWeight: 500
                }}>
                  {userInfo.ClientCode}
                </span>
              </div>
              
              <button
                onClick={handleLogout}
                style={{
                  background: 'linear-gradient(45deg, #FF416C, #FF4B2B)',
                  color: 'white',
                  border: 'none',
                  padding: '8px 20px',
                  borderRadius: '20px',
                  fontWeight: 500,
                  display: 'flex',
                  alignItems: 'center',
                  transition: 'all 0.3s',
                  boxShadow: '0 4px 15px rgba(255, 65, 108, 0.2)'
                }}
                onMouseOver={e => {
                  e.currentTarget.style.transform = 'translateY(-2px)';
                  e.currentTarget.style.boxShadow = '0 6px 20px rgba(255, 65, 108, 0.3)';
                }}
                onMouseOut={e => {
                  e.currentTarget.style.transform = 'translateY(0)';
                  e.currentTarget.style.boxShadow = '0 4px 15px rgba(255, 65, 108, 0.2)';
                }}
              >
                <i className="fas fa-sign-out-alt me-2"></i>
                Logout
              </button>
            </div>
          )}
        </div>
      </div>
    </header>
  );
};

export default Header;
